                                    🌙 Dark
                                </span>
                            </div>
                        </div>
                    </div>
                </div>
    
                {/* Additional Settings */}
                <div className="p-8">
                    <h3 className={`text-xl font-bold ${isDarkMode ? 'text-white' : 'text-gray-900'} flex items-center mb-6 transition-colors duration-300`}>
