                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Grading Preferences */}
                        <div className={`p-6 ${isDarkMode ? 'bg-gray-700 border-gray-600' : 'bg-gray-50 border-gray-200'} rounded-xl border transition-colors duration-300`}>
